# =====================================================
# 鵬鵬的退休星球 v13.4
# 重點：第一階段版面重構、星球首頁、KPI 卡片、退休進度區
# =====================================================

DB_NAME = "etf_portfolio.db"

# 1. 初始化資料庫與專用資料表
conn = sqlite3.connect(DB_NAME, check_same_thread=False)
c = conn.cursor()

c.execute('''
    CREATE TABLE IF NOT EXISTS tx_v74 (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        date TEXT,
        symbol TEXT,
        amount REAL,
        shares REAL,
        fee REAL
    )
''')

c.execute('''
    CREATE TABLE IF NOT EXISTS dividend_v74 (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        date TEXT,
        symbol TEXT,
        dividend_amount REAL
    )
''')

c.execute('''
    CREATE TABLE IF NOT EXISTS est_dividend_v90 (
        symbol TEXT PRIMARY KEY,
        frequency TEXT,
        cash_per_time REAL,
        stock_per_time REAL
    )
''')

c.execute('''
    CREATE TABLE IF NOT EXISTS dividend_calendar_v101 (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        symbol TEXT,
        ex_dividend_date TEXT,
        payment_date TEXT,
        dividend_per_share REAL,
        note TEXT
    )
''')

c.execute('''
    CREATE TABLE IF NOT EXISTS sell_tx_v104 (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        date TEXT,
        symbol TEXT,
        shares REAL,
        sell_price REAL,
        fee REAL,
        tax REAL
    )
''')

c.execute('''
    CREATE TABLE IF NOT EXISTS cash_account_v104 (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        date TEXT,
        amount REAL,
        note TEXT
    )
''')

conn.commit()

# 2. 網頁佈局設定
