                c_4.write(f"單次股票: {rstock:.3f} 元")
                if c_btn.button("🗑️ 清除", key=f"del_est_{rsym}"):
                    c.execute("DELETE FROM est_dividend_v90 WHERE symbol = ?", (rsym,))
